import Image from "next/image";
import Link from "next/link";
import { Asterisk } from "lucide-react";
import { getProjectBySlug } from "@/data/projects";

/**
 * Page de détail d'un projet, affichant une image principale et un titre stylisé.
 * @param param0 - Les paramètres de la route, incluant le slug du projet.
 * @returns Un composant React représentant la page de détail du projet.
 */
export default async function ProjectDetailPage({ params }: { params: Promise<{ slug: string }> }) {
  const { slug } = await params; // Récupération du slug à partir des paramètres de la route (slug = nom du projet dans l'URL)
  const project = getProjectBySlug(slug);

  if (!project) {
    return (
      <main className="min-h-screen bg-[#121212] flex items-center justify-center">
        <p className="text-white">Projet non trouvé</p>
      </main>
    );
  }

  return (
    <main className="min-h-screen">
      {/* =========================================
          IMAGE DU PROJET AVEC NAVIGATION
          ========================================= */}
      <section className="relative w-full px-2 pt-2">
        {/* Conteneur image - hauteur définie */}
        <div className="relative w-full h-[calc(60vh-16px)] md:h-[calc(75vh-16px)] overflow-hidden">
          {/* Image du projet - cover pour remplir le cadre */}
          <Image
            src={project.image}
            alt={`${project.title} - Project showcase`}
            fill
            className="object-cover"
            priority
          />

          {/* Navigation overlay - toujours visible, en bas de l'image */}
          <nav className="absolute bottom-2 left-0 right-0 flex justify-between items-center px-2 md:px-8">
            <Link href="/projects" className="text-xs md:text-sm tracking-[0.25em] uppercase text-white font-bold">
              Back
            </Link>
            <Link href="/" className="text-xs md:text-sm tracking-[0.25em] uppercase text-white font-bold">
              Home
            </Link>
            <span className="text-xs md:text-sm tracking-[0.25em] uppercase text-white font-bold">
              Next
            </span>
          </nav>
        </div>
      </section>

      {/* =========================================
          TITRE DU PROJET AVEC ÉTOILES
          ========================================= */}
      <section className="bg-[#f4f5f0] px-4 mt-5 md:mt-20">
        <div className="flex items-center justify-center gap-4">
          <Asterisk strokeWidth={1} className="h-10 w-10 md:h-28 md:w-28 text-[#1e1f1f] md:ml-5" />
          <h1 className="font-script text-4xl md:text-[10rem] text-gray-900 whitespace-nowrap">
            {project.title}
          </h1>
          <Asterisk strokeWidth={1} className="h-10 w-10 md:h-28 md:w-28 text-[#1e1f1f] md:ml-5" />
        </div>
      </section>
    </main>
  );
}